+    }
+    let quarantined = report
+        .fixture_results
+        .iter()
+        .filter(|result| result.nondeterministic_engine_count > 0)
+        .count() as u64;
+    (
+        report.summary.divergent_fixtures.saturating_sub(quarantined),
+        0,
+    )
+}
