+    let script = format!(
+        r#"#!/bin/sh
+set -eu
+cat >/dev/null
+counter_file='{counter}'
+count=0
+if [ -f "$counter_file" ]; then
+  count=$(cat "$counter_file")
+fi
+count=$((count + 1))
+printf "%s" "$count" > "$counter_file"
+if [ "$count" -eq 1 ]; then
+  hash="{bad_hash}"
